    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        std::string stem;
        std::cin >> stem;
        if (i > 0) std::cout << ' ';
        std::cout << "-l" << stem;
    }
    std::cout << '\n';
    return 0;
