#include <iostream>
#include <string>

bool isValid(const std::string& name) {
    if (name.substr(0, 3) == "lib") return false;
    if (name.size() >= 2 && name.substr(name.size() - 2) == ".a") return false;
    if (name.substr(0, 2) == "-l") return false;
    return true;
}

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        std::string name;
        std::cin >> name;
        std::cout << (isValid(name) ? "valid" : "invalid") << '\n';
    }
    return 0;
}
